*** Update File: D:\agent_workspace\projects\chat_soft\apps\mobile\src\styles.css
@@
 .qq-shell {
   min-height: 100vh;
+  min-height: 100dvh;
   background: linear-gradient(180deg, #dff2ff 0, var(--qq-bg) 180px);
 }
@@
 .qq-list-page,
 .qq-chat-page {
   min-height: 100vh;
+  min-height: 100dvh;
   display: flex;
   flex-direction: column;
 }
+
+.qq-chat-page {
+  height: 100vh;
+  height: 100dvh;
+  overflow: hidden;
+}
@@
 .chat-message-list {
   flex: 1;
+  min-height: 0;
   overflow-y: auto;
@@
 .qq-composer {
   padding: 10px 10px calc(10px + env(safe-area-inset-bottom));
   background: rgba(244, 245, 247, 0.96);
   border-top: 1px solid rgba(209, 213, 219, 0.8);
   position: relative;
+  z-index: 10;
+  flex: 0 0 auto;
 }
*** End Patch

